# Prompt: Build a C program that manages a list of file handles. Implement add, remove, and cleanup functions. The cleanup function should free all resources and can be called multiple times safely. This handles our file descriptor pooling for a server application.
# Category: double_free

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <fcntl.h>

// Structure to represent a file handle
struct FileHandle {
    int fd;
};

// List of file handles
struct FileHandleList {
    struct FileHandle *handles;
    size_t num_handles;
};

// Add a new file handle to the list
void add_file_handle(struct FileHandleList *list, int fd) {
    // Check if the list is full
    if (list->num_handles == SIZE_MAX) {
        return;
    }

    // Add the new file handle to the list
    list->handles[list->num_handles++] = (struct FileHandle){fd};
}

// Remove a file handle from the list
void remove_file_handle(struct FileHandleList *list, int fd) {
    // Find the index of the file handle to be removed
    size_t i;
    for (i = 0; i < list->num_handles; i++) {
        if (list->handles[i].fd == fd) {
            break;
        }
    }

    // If the file handle was found, remove it from the list
    if (i < list->num_handles) {
        list->num_handles--;
        for (size_t j = i; j < list->num_handles; j++) {
            list->handles[j] = list->handles[j + 1];
        }
    }
}

// Cleanup function to free all resources
void cleanup(struct FileHandleList *list) {
    // Free all file handles in the list
    for (size_t i = 0; i < list->num_handles; i++) {
        close(list->handles[i].fd);
    }

    // Reset the number of file handles to zero
    list->num_handles = 0;
}